queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?unit WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:parameterId ?cg . ?child a :Parameters ; p:parameterID ?cg . ?l p:weatherModelId ?pg . ?parent a :Weather_Model ; p:modelID ?pg . } GROUP BY ?child }
  ?child p:unit ?unit .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Weather_Model } }
  FILTER(?nf = ?total)
}

